features.snippet:
localparam X=1;
generate
if (X == 1)
  $info("X is 1");
else
  $info("X is not 1");
endgenerate

localparam P=1;
generate
if (P != 1)
  $error("Invalid parameter");
endgenerate

localparam W=1;
generate
if (W == 0)
  $warning("W is zero");
endgenerate

localparam F=1;
generate
if (F != 1)
  $fatal(0, "F must be 1");
endgenerate
